public sealed class GitHubBoardReaderTests
{
    private static readonly DateTimeOffset FixedNow = new(2026, 05, 27, 12, 0, 0, TimeSpan.Zero);
    private static readonly TimeSpan DefaultPollInterval = TimeSpan.FromMinutes(10);

    private static readonly ILogger<GitHubBoardReader> NullLogger = NullLogger<GitHubBoardReader>.Instance;

    // -----------------------------------------------------------------------------
    // Cache Hit Scenarios
    // -----------------------------------------------------------------------------

    [Fact]
    public async Task GetCurrentAsync_WhenCacheHasRecentData_ReturnsCachedSnapshot()
    {
        // Arrange
        using var cache = new BoardSnapshotCache();
        var cachedSnapshot = BuildTestSnapshot(ticketId: 1);
        
        cache.Update(cachedSnapshot, FixedNow);

        var client = new FakeGitHubIssuesClient(Array.Empty<GitHubIssueRecord>());
        var reader = BuildReader(cache, client, BuildOptions(pollInterval: TimeSpan.FromDays(365)), FixedNow);

        // Act
        var result = await reader.GetCurrentAsync(CancellationToken.None);

        // Assert
        result.Should().BeSameAs(cachedSnapshot);
        client.CallCount.Should().Be(0); // Client should not be called
    }

    // -----------------------------------------------------------------------------
    // Cache Miss Scenarios
    // -----------------------------------------------------------------------------

    [Fact]
    public async Task GetCurrentAsync_WhenCacheIsEmpty_PollGitHubAndReturnsSnapshot()
    {
        // Arrange
        using var cache = new BoardSnapshotCache();
        // Cache is empty (default state)
        
        var records = new List<GitHubIssueRecord>
        {
            new(1, "Test Issue", new List<string> { "status:created", "agent:pm" }, FixedNow.AddHours(-1),
                "https://github.com/AskmethatFR/agent-dashboard/issues/1", FixedNow.AddHours(-1), null)
        };
        var client = new FakeGitHubIssuesClient(records);
        var reader = BuildReader(cache, client, BuildOptions(), FixedNow);

        // Act
        var result = await reader.GetCurrentAsync(CancellationToken.None);

        // Assert
        result.Should().NotBeNull();
        result.Tickets.Should().HaveCount(1);
        client.CallCount.Should().Be(1); // Client should be called once
        cache.GetLatest().Should().BeSameAs(result); // Cache should be updated
    }

    [Fact]
    public async Task GetCurrentAsync_WhenCacheIsStale_PollGitHubAndUpdatesCache()
    {
        // Arrange
        using var cache = new BoardSnapshotCache();
        var oldSnapshot = BuildTestSnapshot(ticketId: 1);
        cache.Update(oldSnapshot, FixedNow);

        var timeAfterCache = FixedNow.AddMilliseconds(150);

        var records = new List<GitHubIssueRecord>
        {
            new(2, "New Issue", new List<string> { "status:created", "agent:pm" }, FixedNow,
                "https://github.com/AskmethatFR/agent-dashboard/issues/2", FixedNow, null)
        };
        var client = new FakeGitHubIssuesClient(records);
        var reader = BuildReader(cache, client, BuildOptions(pollInterval: TimeSpan.FromMilliseconds(100)), timeAfterCache);

        // Act
        var result = await reader.GetCurrentAsync(CancellationToken.None);

        // Assert
        result.Should().NotBeNull();
        result.Tickets.Should().HaveCount(1);
        result.Tickets[0].Id.Value.Should().Be(2); // New ticket
        client.CallCount.Should().Be(1); // Client should be called
        cache.GetLatest().Should().BeSameAs(result); // Cache should be updated
    }

