    // Helper Methods
    // -----------------------------------------------------------------------------

    private static GitHubPollingOptions BuildOptions(TimeSpan? pollInterval = null)
    {
        return new GitHubPollingOptions
        {
            Token = "test-token",
            RepositoryOwner = "test-owner",
            RepositoryName = "test-repo",
            PollInterval = pollInterval ?? DefaultPollInterval
        };
    }

    private static GitHubBoardReader BuildReader(
        BoardSnapshotCache cache,
        IGitHubIssuesClient client,
        GitHubPollingOptions options,
        DateTimeOffset now,
        IBoardSnapshotUpdater snapshotUpdater = null)
    {
        var timeProvider = new ManualTimeProvider(now);
        var updater = snapshotUpdater ?? new BoardSnapshotUpdater(cache);
        return new GitHubBoardReader(cache, client, updater, options.PollInterval, timeProvider, NullLogger);
    }

    private static BoardSnapshot BuildTestSnapshot(int ticketId = 1)
    {
        var column = new BoardColumn(new BoardColumnId("CREATED"), new BoardColumnLabel("Created"));
        var agent = new Agent(new AgentId("pm"), new AgentName("Project Manager"), new AgentGlyph("PM"), new AgentRole("project-manager"));
        var ticket = TicketSnapshot.Open(
            new TicketId(ticketId),
            column.Id,
            new TicketTitle("Test TicketSnapshot"),
            agent.Id,
            new Retry(0),
            new Age(TimeSpan.Zero),
            thinking: false,
            freshness: TicketFreshness.Neutral);

        return new BoardSnapshot(
            new[] { column },
            new[] { ticket },
            new[] { agent });
    }

    // Manual time provider that allows us to control the current time
    private sealed class ManualTimeProvider : TimeProvider
    {
        private readonly DateTimeOffset _fixedTime;

        public ManualTimeProvider(DateTimeOffset fixedTime)
        {
            _fixedTime = fixedTime;
        }

        public override DateTimeOffset GetUtcNow() => _fixedTime;
    }
